#include <stdio.h>
#include <stdlib.h>
#include <math.h>

// Function to calculate the sum of squares of divisors
int sumOfSquares(int n) {
    int sum = 0;
    for (int i = 1; i * i <= n; i++) {
        if (n % i == 0) {
            sum += i * i;
            if (i * i != n) {
                sum += (n / i) * (n / i);
            }
        }
    }
    return sum;
}

// Function to perform depth-first search
void dfs(int node, int parent, int *beautiful, int *ugly, int **graph, int *visited, int *length, int *totalLength) {
    visited[node] = 1;
    if (beautiful[node] != 0) {
        *length += 1;
    } else {
        *ugly += 1;
    }
    for (int i = 0; i < graph[node][0]; i++) {
        int child = graph[node][i + 1];
        if (!visited[child]) {
            dfs(child, node, beautiful, ugly, graph, visited, length, totalLength);
        }
    }
    if (*length >= *ugly) {
        *totalLength += *length;
    }
    *length -= 1;
    if (beautiful[node] != 0) {
        *beautiful -= 1;
    } else {
        *ugly -= 1;
    }
    visited[node] = 0;
}

