    for (int i = 0; i < N; i++) {
        graph[i] = (int *)malloc(2 * sizeof(int));
        graph[i][0] = 0;
    }
    for (int i = 0; i < N - 1; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        u--;
        v--;
        graph[u][0] += 1;
        graph[v][0] += 1;
        graph[u] = (int *)realloc(graph[u], (graph[u][0] + 1) * sizeof(int));
        graph[v] = (int *)realloc(graph[v], (graph[v][0] + 1) * sizeof(int));
        graph[u][graph[u][0]] = v;
        graph[v][graph[v][0]] = u;
    }
    int *beautiful = (int *)malloc(N * sizeof(int));
    int *ugly = (int *)malloc(N * sizeof(int));
    for (int i = 0; i < N; i++) {
        int num;
        scanf("%d", &num);
        int sum = sumOfSquares(num);
